use std::sync::{Arc, Mutex};
use std::thread;

struct Inventory {
    product_name: String,
    quantity: i32,
}

impl Inventory {
    fn new(product_name: &str) -> Self {
        Inventory {
            product_name: product_name.to_string(),
            quantity: 0,
        }
    }

    fn check_stock(&self, count: i32) {
        let lock = self.lock().unwrap();
        if *lock >= count {
            println!("Product {} is in stock", self.product_name);
            let mut new_count = (*lock - count).to_owned();
            drop(lock);
            println!("New quantity of {}: {}", self.product_name, new_count);
        } else {
            println!("Out of stock");
        }
    }

    fn decrement_inventory(&self) -> i32 {
        let lock = self.lock().unwrap();
        *lock -= 1;
        let count = (*lock).to_owned();
        drop(lock);
        count
    }

    fn lock(&self) -> std::sync::MutexGuard<i32> {
        Arc::clone(&self.quantity).lock()
    }
}

